export const getAllPizzaReducer=(state ={},action)=>{
    switch(action.type)
    {
        case 'GET_PIZZAS_REQUEST':
            return{
                ... state
            }
            case 'GET_PIZZAS_SUCSESS':
                return {
                    pizzas:action.payload
                }
                case 'GET_PIZZAS_FAIL':
                    return {
                        error:action.payload
                    }
